[dependencies]
clap = { version = "4", features = ["derive"] }
anyhow = "1"
regex = "1"
serde = { version = "1", features = ["derive"] }
serde_json = "1"

use serde::Serialize;

#[derive(Debug, Clone, Serialize)]
pub struct AnalysisResult {
    pub level: String,
    pub pattern: String,
    pub count: usize,
    pub samples: Vec<String>,
}

use crate::types::AnalysisResult;

pub fn print_results(results: &[AnalysisResult], format: &str) -> anyhow::Result<()> {
    match format {
        "json" => print_json(results),
        _ => { print_text(results); Ok(()) }
    }
}

fn print_text(results: &[AnalysisResult]) {
    println!("=== Log Analysis Results ===");
    for r in results {
        println!("[{}] {} - {} occurrences", r.level, r.pattern, r.count);
        for sample in &r.samples {
            println!("  > {}", sample);
        }
    }
    println!("Total patterns: {}", results.len());
}

fn print_json(results: &[AnalysisResult]) -> anyhow::Result<()> {
    let json = serde_json::to_string_pretty(results)?;
    println!("{}", json);
    Ok(())
}

#[derive(Parser)]
struct Args {
    /// Log file to analyze
    file: String,
    /// Minimum severity level
    #[arg(short, long, default_value = "warn")]
    level: String,
    /// Output format: text or json
    #[arg(short, long, default_value = "text")]
    format: String,
}

fn main() -> anyhow::Result<()> {
    let args = Args::parse();
    let results = analyzer::analyze(&args.file, &args.level)?;
    output::print_results(&results, &args.format)
}
